parameters.old_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives email notifications.
 * Designed for email as the current channel, extensible for future channels.
 */

import type { NotificationType } from './notification.js';

/**
 * How often to receive email digests.
 * 'immediate' sends each notification as it happens.
 * 'daily' and 'weekly' batch notifications into digest emails.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_update',
];

/**
 * Default email preferences for new users.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

