/**
 * User notification preferences model.
 *
 * Supports per-channel notification settings for email, SMS, and webhook.
 *
 * History: Originally designed for email-only (Session 3). Expanded to
 * multi-channel after SMS support was added (Session 8) and webhook
 * adapter was created (Session 6). The email-only assumption is no longer
 * valid — each channel now has its own independent preferences.
 */

import type { NotificationType } from './notification.js';

/**
 * How often to receive email digests.
 * 'immediate' sends each notification as it happens.
 * 'daily' and 'weekly' batch notifications into digest emails.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification settings.
 * SMS does not support frequency/digest — messages are always immediate.
 */
export interface SmsPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification settings.
 * Webhooks are always immediate — no digest mode.
 */
export interface WebhookPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences.
 * Each channel has independent settings. Missing channel preferences
 * are treated as default-enabled (backward compatible).
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_update',
];

/**
 * Default email preferences for new users.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Default SMS preferences for new users.
 */
export function getDefaultSmsPreferences(): SmsPreferences {
  return {
    enabled: true,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Default webhook preferences for new users.
 */
export function getDefaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: true,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

